function parseStudents(){
  const r={};
  for(const[key,arr] of Object.entries(DATA.g)){
    const[di,ci]=key.split("-").map(Number);
    if(!r[di])r[di]={};
    r[di][ci]=arr.map((s,idx)=>({
      key:`${key}-${idx}`,name:s[0],id:s[1],nat:DATA.n[s[2]],
      college:DATA.c[ci],collegeIdx:ci,src:"original",
      rowNum:s[3],tag:s[4]||0
    }));
  }
  return r;
}

